import*as React from"react";import{clamp}from"../helpers/math";import{rangeIncrement}from"../helpers/range";const usePagination=({currentPage:s=1,siblingCount:m=1,boundaryCount:o=1,totalPages:p=1}={})=>React.useMemo(()=>{var e=rangeIncrement(1,Math.min(o,p)),n=rangeIncrement(Math.max(p-o+1,o+1),p),t=clamp(s-m,o+2,p-o-1-2*m),a=Math.min(Math.max(s+m,o+2+2*m),0<n.length?n[0]-2:p-1);const r=e;return o+2<t?r.push("start-ellipsis"):o+1<p-o&&r.push(o+1),r.push(...rangeIncrement(t,a)),a<p-o-1?r.push("end-ellipsis"):o<p-o&&r.push(p-o),r.push(...n),r},[s,p,m,o]);export{usePagination};